import { useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";

function Register() {
  const [user, setUser] = useState({
    name: "",
    email: "",
    password: "",
    passwordConfirm: "",
    role: "user",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setUser({ ...user, [e.target.name]: e.target.value });
    setError("");
  };

  const submit = async (e) => {
    e.preventDefault();

    if (user.password.length < 6) {
      setError("Password must be at least 6 characters");
      return;
    }

    if (user.password !== user.passwordConfirm) {
      setError("Passwords do not match");
      return;
    }

    setLoading(true);

    try {
      await axios.post("http://localhost:8070/api/auth/register", {
        name: user.name,
        email: user.email,
        password: user.password,
        role: user.role
      });
      navigate("/login");
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, var(--bg) 0%, var(--bg-hover) 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      padding: "20px"
    }}>
      <div style={{
        width: "100%",
        maxWidth: "480px",
        backgroundColor: "var(--bg-card)",
        borderRadius: "12px",
        border: "1px solid var(--border)",
        boxShadow: "0 12px 32px rgba(0,0,0,0.08)",
        padding: "48px 40px",
        animation: "slideUp 0.4s ease"
      }}>
        {/* Header */}
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          <img src="/logo.svg" alt="Leaf Lanka" style={{
            width: "60px",
            height: "60px",
            objectFit: "contain",
            borderRadius: "8px",
            margin: "0 auto 20px",
            display: "block"
          }} />
          <h1 style={{
            fontSize: "28px",
            fontWeight: 700,
            color: "var(--text)",
            margin: "0 0 8px 0",
            letterSpacing: "-0.5px"
          }}>
            Create Account
          </h1>
          <p style={{
            fontSize: "14px",
            color: "var(--text-muted)",
            margin: 0
          }}>
            Join Leaf Lanka to explore premium vehicles
          </p>
        </div>

        {/* Error Alert */}
        {error && (
          <div style={{
            padding: "12px 16px",
            backgroundColor: "#ffebee",
            border: "1px solid #ffcdd2",
            borderRadius: "8px",
            marginBottom: "24px",
            color: "#c62828",
            fontSize: "13px",
            fontWeight: 500
          }}>
            {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={submit} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
          {/* Name Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Full Name
            </label>
            <input
              name="name"
              placeholder="John Doe"
              value={user.name}
              onChange={handleChange}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
          </div>

          {/* Email Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Email Address
            </label>
            <input
              name="email"
              type="email"
              placeholder="your@email.com"
              value={user.email}
              onChange={handleChange}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
          </div>

          {/* Password Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Password
            </label>
            <input
              name="password"
              type="password"
              placeholder="••••••••"
              value={user.password}
              onChange={handleChange}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
            <p style={{ fontSize: "12px", color: "var(--text-muted)", marginTop: "6px", margin: "6px 0 0 0" }}>
              Minimum 6 characters
            </p>
          </div>

          {/* Confirm Password Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Confirm Password
            </label>
            <input
              name="passwordConfirm"
              type="password"
              placeholder="••••••••"
              value={user.passwordConfirm}
              onChange={handleChange}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
          </div>

          {/* Role Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Account Type
            </label>
            <select
              name="role"
              value={user.role}
              onChange={handleChange}
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none",
                cursor: "pointer"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            >
              <option value="user">Customer</option>
              <option value="staff">Staff</option>
            </select>
          </div>

          {/* Register Button */}
          <button
            type="submit"
            disabled={loading}
            style={{
              padding: "12px 16px",
              fontSize: "14px",
              fontWeight: 700,
              letterSpacing: "0.3px",
              backgroundColor: loading ? "var(--text-muted)" : "var(--primary)",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: loading ? "not-allowed" : "pointer",
              transition: "all 0.2s",
              marginTop: "8px"
            }}
            onMouseEnter={(e) => {
              if (!loading) {
                e.currentTarget.style.backgroundColor = "var(--primary-hover)";
                e.currentTarget.style.transform = "translateY(-2px)";
                e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)";
              }
            }}
            onMouseLeave={(e) => {
              if (!loading) {
                e.currentTarget.style.backgroundColor = "var(--primary)";
                e.currentTarget.style.transform = "translateY(0)";
                e.currentTarget.style.boxShadow = "none";
              }
            }}
          >
            {loading ? "Creating Account..." : "Create Account"}
          </button>
        </form>

        {/* Divider */}
        <div style={{
          height: "1px",
          backgroundColor: "var(--border)",
          margin: "32px 0"
        }} />

        {/* Login Link */}
        <p style={{
          textAlign: "center",
          fontSize: "14px",
          color: "var(--text-muted)",
          margin: 0
        }}>
          Already have an account?{" "}
          <Link to="/login" style={{
            color: "var(--primary)",
            fontWeight: 600,
            textDecoration: "none",
            transition: "opacity 0.2s"
          }}
          onMouseEnter={(e) => e.currentTarget.style.opacity = "0.8"}
          onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}
          >
            Sign In
          </Link>
        </p>
      </div>

      <style>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
}

export default Register;
